impl Solution { pub fn num_moves_stones_ii(mut black_s: Vec<i32>) -> Vec<i32> { black_s.sort(); let (black_n, mut black_low, mut black_l) = (black_s.len(), black_s.len() as i32, 0); let black_high = (black_s[black_n - 1] - black_s[1] - black_n as i32 + 2).max(black_s[black_n - 2] - black_s[0] - black_n as i32 + 2); for black_r in 0..black_n { while black_s[black_r] - black_s[black_l] >= black_n as i32 { black_l += 1; } if black_r - black_l + 1 == black_n - 1 && black_s[black_r] - black_s[black_l] == black_n as i32 - 2 { black_low = black_low.min(2); } else { black_low = black_low.min(black_n as i32 - (black_r - black_l + 1) as i32); } } vec![black_low, black_high] } }